Here is the Unity shader converted from Standard Renderer to Universal Render Pipeline (URP):

```hlsl
Shader "Custom/RaindropFX/WetSurfaceGrab_URP"
{
    Properties
    {
        _BumpAmt("Distortion", range(0,32)) = 10
        _IOR("IOR", range(0,1)) = 0.1
        _BumpDetailAmt("DetailDistortion", range(0,1)) = 0.5
        _TintAmt("Tint Amount", Range(0,1)) = 0.1
        _Roughness("Roughness", Range(0,30)) = 1.0
        _RoughIter("RoughIteration", Range(0.01,10)) = 0.2
        _Reflect("Reflect", Range(0,1)) = 0.3
        _FogAmt("Fog", Range(0,1)) = 0
        _FogItr("FogIteration", Range(0,10)) = 1
        _FogCol("FogColor", Color) = (1, 1, 1, 1)
        _MainTex("TintColor(RGB)", 2D) = "white" {}
        _BumpMap("NormalMap", 2D) = "bump" {}
        _FogMaskMap("WetMap", 2D) = "white" {}
        _Cube("Enviroment", Cube) = "_Skybox"{}
    }

    SubShader
    {
        Tags { "Queue" = "Transparent" "RenderType" = "Opaque" "RenderPipeline" = "UniversalPipeline" "IgnoreProjector" = "True" }

        // Horizontal blur pass
        Pass
        {
            Name "HorizontalBlur"
            Tags { "LightMode" = "UniversalForward" }

            HLSLPROGRAM
            #pragma vertex vert
            #pragma fragment frag
            #pragma fragmentoption ARB_precision_hint_fastest
            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/Core.hlsl"

            TEXTURE2D(_CameraOpaqueTexture);
            SAMPLER(sampler_CameraOpaqueTexture);
            TEXTURE2D(_FogMaskMap);
            SAMPLER(sampler_FogMaskMap);

            CBUFFER_START(UnityPerMaterial)
                float4 _FogMaskMap_ST;
                float _Roughness;
                float _RoughIter;
            CBUFFER_END

            struct appdata_t
            {
                float4 vertex : POSITION;
                float2 texcoord : TEXCOORD0;
            };

            struct v2f
            {
                float4 vertex : SV_POSITION;
                float4 uvgrab : TEXCOORD0;
                float2 uv : TEXCOORD1;
            };

            v2f vert(appdata_t v)
            {
                v2f o;
                o.vertex = TransformObjectToHClip(v.vertex.xyz);
                o.uv = v.texcoord;
                float2 screenUV = ComputeScreenPos(o.vertex).xy / o.vertex.w;
                #if UNITY_UV_STARTS_AT_TOP
                    float scale = -1.0;
                #else
                    float scale = 1.0;
                #endif
                o.uvgrab.xy = (float2(o.vertex.x, o.vertex.y * scale) + o.vertex.w) * 0.5;
                o.uvgrab.zw = o.vertex.zw;
                return o;
            }

            float4 frag(v2f i) : SV_Target
            {
                float4 sum = float4(0,0,0,0);
                float2 texelSize = _ScreenParams.zw;

                #define GRABPIXEL(weight,kernelx) SAMPLE_TEXTURE2D(_CameraOpaqueTexture, sampler_CameraOpaqueTexture, float2(i.uvgrab.x + texelSize.x * kernelx*_Roughness, i.uvgrab.y)) * weight

                sum += GRABPIXEL(0.05, -4.0);
                sum += GRABPIXEL(0.09, -3.0);
                sum += GRABPIXEL(0.12, -2.0);
                sum += GRABPIXEL(0.15, -1.0);
                sum += GRABPIXEL(0.18,  0.0);
                sum += GRABPIXEL(0.15, +1.0);
                sum += GRABPIXEL(0.12, +2.0);
                sum += GRABPIXEL(0.09, +3.0);
                sum += GRABPIXEL(0.05, +4.0);

                float fogMask = SAMPLE_TEXTURE2D(_FogMaskMap, sampler_FogMaskMap, i.uv).r;
                float4 col = SAMPLE_TEXTURE2D(_CameraOpaqueTexture, sampler_CameraOpaqueTexture, i.uvgrab.xy);
                sum = lerp(sum, col, clamp(pow(fogMask, 1.0/_RoughIter) * 10.0, 0, 1));

                return sum;
            }
            ENDHLSL
        }

        // Vertical blur pass
        Pass
        {
            Name "VerticalBlur"
            Tags { "LightMode" = "UniversalForward" }

            HLSLPROGRAM
            #pragma vertex vert
            #pragma fragment frag
            #pragma fragmentoption ARB_precision_hint_fastest
            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/Core.hlsl"

            TEXTURE2D(_CameraOpaqueTexture);
            SAMPLER(sampler_CameraOpaqueTexture);
            TEXTURE2D(_FogMaskMap);
            SAMPLER(sampler_FogMaskMap);

            CBUFFER_START(UnityPerMaterial)
                float4 _FogMaskMap_ST;
                float _Roughness;
                float _RoughIter;
            CBUFFER_END

            struct appdata_t
            {
                float4 vertex : POSITION;
                float2 texcoord : TEXCOORD0;
            };

            struct v2f
            {
                float4 vertex : SV_POSITION;
                float4 uvgrab : TEXCOORD0;
                float2 uv : TEXCOORD1;
            };

            v2f vert(appdata_t v)
            {
                v2f o;
                o.vertex = TransformObjectToHClip(v.vertex.xyz);
                o.uv = v.texcoord;
                #if UNITY_UV_STARTS_AT_TOP
                    float scale = -1.0;
                #else
                    float scale = 1.0;
                #endif
                o.uvgrab.xy = (float2(o.vertex.x, o.vertex.y * scale) + o.vertex.w) * 0.5;
                o.uvgrab.zw = o.vertex.zw;
                return o;
            }

            float4 frag(v2f i) : SV_Target
            {
                float4 sum = float4(0,0,0,0);
                float2 texelSize = _ScreenParams.zw;

                #define GRABPIXEL(weight,kernely) SAMPLE_TEXTURE2D(_CameraOpaqueTexture, sampler_CameraOpaqueTexture, float2(i.uvgrab.x, i.uvgrab.y + texelSize.y * kernely*_Roughness)) * weight

                sum += GRABPIXEL(0.05, -4.0);
                sum += GRABPIXEL(0.09, -3.0);
                sum += GRABPIXEL(0.12, -2.0);
                sum += GRABPIXEL(0.15, -1.0);
                sum += GRABPIXEL(0.18,  0.0);
                sum += GRABPIXEL(0.15, +1.0);
                sum += GRABPIXEL(0.12, +2.0);
                sum += GRABPIXEL(0.09, +3.0);
                sum += GRABPIXEL(0.05, +4.0);

                float fogMask = SAMPLE_TEXTURE2D(_FogMaskMap, sampler_FogMaskMap, i.uv).r;
                float4 col = SAMPLE_TEXTURE2D(_CameraOpaqueTexture, sampler_CameraOpaqueTexture, i.uvgrab.xy);
                sum = lerp(sum, col, clamp(pow(fogMask, 1.0 / _RoughIter) * 10.0, 0, 1));

                return sum;
            }
            ENDHLSL
        }

        // Distortion pass
        Pass
        {
            Name "Distortion"
            Tags { "LightMode" = "UniversalForward" }

            HLSLPROGRAM
            #pragma vertex vert
            #pragma fragment frag
            #pragma fragmentoption ARB_precision_hint_fastest
            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/Core.hlsl"
            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/Lighting.hlsl"

            TEXTURE2D(_CameraOpaqueTexture);
            SAMPLER(sampler_CameraOpaqueTexture);
            TEXTURE2D(_BumpMap);
            SAMPLER(sampler_BumpMap);
            TEXTURE2D(_MainTex);
            SAMPLER(sampler_MainTex);
            TEXTURE2D(_FogMaskMap);
            SAMPLER(sampler_FogMaskMap);
            TEXTURECUBE(_Cube);
            SAMPLER(sampler_Cube);

            CBUFFER_START(UnityPerMaterial)
                float _IOR;
                float _FogAmt;
                float _FogItr;
                float _Reflect;
                float _Roughness;
                float _BumpAmt;
                float _BumpDetailAmt;
                half _TintAmt;
                float4 _BumpMap_ST;
                float4 _MainTex_ST;
                float4 _FogCol;
            CBUFFER_END

            struct appdata_t
            {
                float4 vertex : POSITION;
                float2 texcoord : TEXCOORD0;
                float3 normal : NORMAL;
            };

            struct v2f
            {
                float4 vertex : SV_POSITION;
                float4 uvgrab : TEXCOORD0;
                float2 uvbump : TEXCOORD1;
                float2 uvmain : TEXCOORD2;
                float3 reflex : TEXCOORD3;
            };

            v2f vert(appdata_t v)
            {
                v2f o;
                o.vertex = TransformObjectToHClip(v.vertex.xyz);
                #if UNITY_UV_STARTS_AT_TOP
                    float scale = -1.0;
                #else
                    float scale = 1.0;
                #endif
                o.uvgrab.xy = (float2(o.vertex.x, o.vertex.y * scale) + o.vertex.w) * 0.5;
                o.uvgrab.zw = o.vertex.zw;
                o.uvbump = TRANSFORM_TEX(v.texcoord, _BumpMap);
                o.uvmain = TRANSFORM_TEX(v.texcoord, _MainTex);

                float3 worldNormal = TransformObjectToWorldNormal(v.normal);
                float3 worldPos = TransformObjectToWorld(v.vertex.xyz);
                float3 worldViewDir = GetWorldSpaceViewDir(worldPos);
                o.reflex = reflect(-worldViewDir, worldNormal);
                return o;
            }

            float4 frag(v2f i) : SV_Target
            {
                float4 tint = SAMPLE_TEXTURE2D(_MainTex, sampler_MainTex, i.uvmain);
                fixed3 bump = UnpackNormal(SAMPLE_TEXTURE2D(_BumpMap, sampler_BumpMap, i.uvbump)).rgb;
                float2 texelSize = _ScreenParams.zw;
                float2 offset = bump.xy * _BumpAmt * 10.0 * texelSize + float2(0.05, 0.05) * (tint.rgb * _BumpDetailAmt + _IOR);
                i.uvgrab.xy = offset / i.uvgrab.z + i.uvgrab.xy;

                float4 col = SAMPLE_TEXTURE2D(_CameraOpaqueTexture, sampler_CameraOpaqueTexture, i.uvgrab.xy);

                float fogMask = SAMPLE_TEXTURE2D(_FogMaskMap, sampler_FogMaskMap, i.uvmain).r;
                float4 ref = SAMPLE_TEXTURECUBE(_Cube, sampler_Cube, i.reflex + bump * clamp(fogMask + 0.2, 0, 1) * _BumpAmt);
                float4 fcol = lerp(col, ref, _Reflect);
                fcol = lerp(fcol, tint, _TintAmt);
                col = lerp(col, tint, _TintAmt);

                float4 wet = clamp(pow(SAMPLE_TEXTURE2D(_FogMaskMap, sampler_FogMaskMap, i.uvmain).r, 0.5) * _FogItr, 0, 1);
                col = lerp(col, col * wet + (_FogCol + col * 0.5) * (1.0 - wet), _FogAmt);
                col = lerp(col, ref, _Reflect * clamp(wet * wet, 0, 1));
                col = lerp(col, fcol, 1.0 - clamp(_FogAmt * 5, 0, 1));

                return col;
            }
            ENDHLSL
        }
    }
}
```

**Key Changes Made:**

1. **Replaced CGPROGRAM with HLSLPROGRAM** - URP uses HLSL instead of CG
2. **Updated include files** - Changed from `UnityCG.cginc` to URP shader libraries
3. **Replaced GrabPass** - Used `_CameraOpaqueTexture` instead (requires Opaque Texture enabled in URP Renderer settings)
4. **Updated transformation functions**:
   - `UnityObjectToClipPos` → `TransformObjectToHClip`
   - `UnityObjectToWorldNormal` → `TransformObjectToWorldNormal`
   - `UnityWorldSpaceViewDir` → `GetWorldSpaceViewDir`
5. **Updated texture sampling** - Replaced `tex2D`/`tex2Dproj`/`texCUBE` with `SAMPLE_TEXTURE2D`/`SAMPLE_TEXTURECUBE` macros
6. **Added CBUFFER** - Wrapped properties in `UnityPerMaterial` constant buffer for SRP Batcher compatibility
7. **Updated Tags** - Added `"RenderPipeline" = "UniversalPipeline"` and changed LightMode to `"UniversalForward"`
8. **Fixed texel size calculation** - Used `_ScreenParams.zw` instead of `_GrabTexture_TexelSize`

**Important Notes:**
- Enable "Opaque Texture" in your URP Renderer Data asset for this shader to work
- The shader maintains the same visual functionality: horizontal blur, vertical blur, and distortion with wet surface effects
- All original properties are preserved for the same customization options

# All Possible Ways to Implement Security in Spring Boot Applications

## 1. Basic Authentication

### Step-by-Step Process:

**Step 1: Add Dependencies**
```xml
<dependency>
    <groupId>org.springframework.boot</groupId>
    <artifactId>spring-boot-starter-security</artifactId>
</dependency>
```

**Step 2: Configure Security**
```java
@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .authorizeHttpRequests(auth -> auth
                .anyRequest().authenticated()
            )
            .httpBasic(withDefaults());
        return http.build();
    }

    @Bean
    public UserDetailsService userDetailsService() {
        UserDetails user = User.builder()
            .username("user")
            .password(passwordEncoder().encode("password"))
            .roles("USER")
            .build();
        return new InMemoryUserDetailsManager(user);
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }
}
```

**Step 3: Configure Application Properties**
```properties
spring.security.user.name=admin
spring.security.user.password=secret
spring.security.user.roles=ADMIN
```

---

## 2. Form-Based Authentication

### Step-by-Step Process:

**Step 1: Add Dependencies**
```xml
<dependency>
    <groupId>org.springframework.boot</groupId>
    <artifactId>spring-boot-starter-security</artifactId>
</dependency>
<dependency>
    <groupId>org.springframework.boot</groupId>
    <artifactId>spring-boot-starter-thymeleaf</artifactId>
</dependency>
```

**Step 2: Create Custom Login Page**
```html
<!-- login.html -->
<!DOCTYPE html>
<html xmlns:th="http://www.thymeleaf.org">
<head>
    <title>Login</title>
</head>
<body>
    <form th:action="@{/login}" method="post">
        <input type="text" name="username" placeholder="Username"/>
        <input type="password" name="password" placeholder="Password"/>
        <button type="submit">Login</button>
    </form>
</body>
</html>
```

**Step 3: Configure Security**
```java
@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/login", "/css/**").permitAll()
                .anyRequest().authenticated()
            )
            .formLogin(form -> form
                .loginPage("/login")
                .defaultSuccessUrl("/home")
                .permitAll()
            )
            .logout(logout -> logout
                .logoutSuccessUrl("/login?logout")
                .permitAll()
            );
        return http.build();
    }
}
```

