Here is the corrected MATLAB code snippet for H2 state feedback controller design:

```matlab
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% CE2: Robust Control of an Electromechanical System
%
%% 2.2 Model-Based H2 Controller Design
% In this part, an H2 state feedback controller is designed for the model
% G3 of the active suspension system. The objective is to design a state
% feedback controller such that the sum of the (squared) two-norm of the
% closed-loop transfer functions from the input disturbance to the output
% and to the input of the system is minimized.
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
clc
clear all
close all
load('data3.mat')
G3 = bj(data3, [5, 5, 5, 5, 1]);

%% Convert the discrete-time model G3 to a continuous-time model (use d2c).
G3_c = d2c(G3);

%% Write the state space equations of the closed-loop system.
[A, B, C, D] = ssdata(G3_c); % Obtain state-space matrices from continuous-time model

% System dimensions
[n, m] = size(B); % n: states, m: inputs
p = size(C, 1);   % p: outputs

%% Define YALMIP decision variables
X = sdpvar(n, n, 'symmetric');  % Lyapunov matrix (X > 0)
Y = sdpvar(m, n, 'full');       % Controller variable (Y = K*X)
Q = sdpvar(n, n, 'symmetric');  % Auxiliary variable for H2 cost

%% H2 State Feedback Controller Design using Schur Complement
% The problem: minimize ||T_wy1||_2^2 + ||T_wy2||_2^2
% where y1 = Cx and y2 = -Kx
% 
% Using Schur lemma, we convert to LMI formulation:
% minimize trace(Q)
% subject to:
% 1) Stability LMI: (A-BK)X + X(A-BK)' + BB' < 0
% 2) H2 cost LMI: [Q  (C*X)'; (C*X)  I] > 0
% 3) Coupling constraint: [Q  (Y)'; (Y)  I] > 0

% LMI 1: Stability constraint (using Schur complement)
% (A-BK)X + X(A-BK)' + BB' < 0
% Substituting Y = KX: AX + XA' - BY - Y'B' + BB' < 0
LMI1 = [A*X + X*A' - B*Y - Y'*B' + B*B'  0;
        0                              -eye(n)] < 0;

% LMI 2: H2 cost constraint for output y1 = Cx
% [Q  (C*X)'; (C*X)  I] > 0
LMI2 = [Q        (C*X)';
        C*X      eye(p)] > 0;

% LMI 3: H2 cost constraint for control input y2 = -Kx = -Y*X^(-1)*x
% [Q  Y'; Y  I] > 0
LMI3 = [Q      Y';
        Y      eye(m)] > 0;

% LMI 4: X > 0 (positive definite constraint)
LMI4 = X > eye(n) * 1e-6; % Small regularization for numerical stability

% Combine all LMIs
LMI = [LMI1, LMI2, LMI3, LMI4];

% Objective: minimize trace(Q) (H2 norm squared)
Objective = trace(Q);

%% Solve the SDP problem using YALMIP
ops = sdpsettings('solver', 'sedumi', 'verbose', 1);
% ops = sdpsettings('solver', 'mosek'); % Alternative: use MOSEK solver

disp('Solving H2 State Feedback Controller Design...');
sol = optimize(LMI, Objective, ops);

if sol.problem == 0
    disp('Optimization successful!');

    %% Compute the controller K
    X_val = value(X);
    Y_val = value(Y);
    K = Y_val / X_val;  % State feedback controller: K = Y*X^(-1)

    %% Compute the H2 norm
    H2norm_squared = value(trace(Q));
    H2norm = sqrt(H2norm_squared);

    fprintf('H2 norm of closed-loop system: %.4f\n', H2norm);
    fprintf('Controller gain K:\n');
    disp(K);

else
    error('Optimization failed: %s', sol.info);
end

%% Plot the step response of the closed-loop system
sys_cl = ss(A - B*K, B, C, zeros(size(D))); % Closed-loop system
figure;
step(sys_cl);
grid on;
title('Step Response of H2 Controlled System');
xlabel('Time (s)');
ylabel('Output');

%% Compare with LQR controller
R = 1;
Q_lqr = eye(size(A, 1));
[K_lqr, S, E] = lqr(A, B, Q_lqr, R);

sys_cl_lqr = ss(A - B*K_lqr, B, C, D);
figure;
step(sys_cl_lqr);
grid on;
title('Step Response of LQR Controlled System');
xlabel('Time (s)');
ylabel('Output');

%% Compare both controllers
figure;
step(sys_cl, 'b', sys_cl_lqr, 'r--');
legend('H2 Controller', 'LQR Controller');
grid on;
title('Comparison: H2 vs LQR Controllers');
xlabel('Time (s)');
ylabel('Output');
```

**Key modifications and explanations:**

1. **Proper LMI Formulation**: Used Schur complement to convert the H2 norm minimization into LMIs:
   - Stability LMI ensures closed-loop stability
   - Cost LMIs capture both output channels (y1 = Cx and y2 = -Kx)

2. **Decision Variables**:
   - `X`: Lyapunov matrix (symmetric, positive definite)
   - `Y`: Controller variable (Y = KX)
   - `Q`: Auxiliary variable for H2 cost

3. **Schur Lemma Application**:
   - The constraint `(A-BK)X + X(A-BK)' + BB' < 0` ensures stability
   - The H2 cost is captured through trace minimization with coupling constraints

4. **Controller Recovery**: `K = Y*X^(-1)` after solving the SDP

5. **Numerical Stability**: Added small regularization term to X > 0 constraint

**Mathematical Background:**

The H2 norm minimization problem:
- Minimize `||T_wy1||_2^2 + ||T_wy2||_2^2`
- Where `T_wy1(s) = C(sI - A + BK)^(-1)B` and `T_wy2(s) = -K(sI - A + BK)^(-1)B`

Using the Bounded Real Lemma and Schur complement, this is converted to the LMI formulation shown in the code.

Your solution has several issues:

1. **Wrong Algorithm**: You're trying to find consecutive matches, but the problem asks for a **subsequence** (not necessarily consecutive elements in order).

2. **Hash Collision Issues**: Your hash function can cause collisions - different values might hash to the same index.

3. **Incorrect Logic**: You're modifying the hash tables while iterating, which can give incorrect results.

The correct approach is to use **Longest Common Subsequence (LCS)** with dynamic programming:

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    int n, m;

    // Read first word
    cin >> n;
    vector<int> first(n);
    for (int i = 0; i < n; i++) {
        cin >> first[i];
    }

    // Read second word
    cin >> m;
    vector<int> second(m);
    for (int i = 0; i < m; i++) {
        cin >> second[i];
    }

    // LCS DP table
    vector<vector<int>> dp(n + 1, vector<int>(m + 1, 0));

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            if (first[i-1] == second[j-1]) {
                dp[i][j] = dp[i-1][j-1] + 1;
            } else {
                dp[i][j] = max(dp[i-1][j], dp[i][j-1]);
            }
        }
    }

    cout << dp[n][m] << endl;

    return 0;
}
```

**Key Changes:**
1. **Removed hash function** - we compare values directly
2. **Used standard LCS DP** - `dp[i][j]` represents the LCS length of first `i` elements of word1 and first `j` elements of word2
3. **Transition**: If elements match, extend the subsequence; otherwise, take the maximum of excluding one element from either sequence

**Time Complexity**: O(N × M) = O(1000 × 1000) = O(10^6) - efficient enough
**Space Complexity**: O(N × M)

This solution correctly handles the examples:
- `[1,2,3]` and `[5,3,1,2]` → LCS is `[1,2]` or `[3]` → length 2 (but wait, let me recalculate: 1,2,3 vs 5,3,1,2 - the common subsequence could be 1,2 or 3, so max length is 2... but the expected output is 3. Let me reconsider.)

Actually, looking at the example more carefully:
