                    indices.push(a, b, d);
                    indices.push(a, d, c);
                }
            }

            // Create BufferGeometry
            const geometry = new THREE.BufferGeometry();
            geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
            geometry.setIndex(indices);
            geometry.computeVertexNormals();

            // Create material with vertex colors
            const material = new THREE.MeshPhongMaterial({
                color: 0x00aaff,
                side: THREE.DoubleSide,
                shininess: 100,
                flatShading: false
            });

            // Create mesh
            const mesh = new THREE.Mesh(geometry, material);

            // Create wireframe
            const wireframeGeometry = new THREE.WireframeGeometry(geometry);
            const wireframeMaterial = new THREE.LineBasicMaterial({ color: 0x00ffff, opacity: 0.3, transparent: true });
            const wireframe = new THREE.LineSegments(wireframeGeometry, wireframeMaterial);

            return { mesh, wireframe };
        }

        // Plot function
        function plotFunction(func) {
            // Remove previous mesh
            if (currentMesh) {
                scene.remove(currentMesh);
                currentMesh.geometry.dispose();
                currentMesh.material.dispose();
            }
            if (wireframeMesh) {
                scene.remove(wireframeMesh);
                wireframeMesh.geometry.dispose();
                wireframeMesh.material.dispose();
            }

            // Create new mesh
            const { mesh, wireframe } = createFunctionMesh(func);
            currentMesh = mesh;
            wireframeMesh = wireframe;

            scene.add(currentMesh);
            scene.add(wireframeMesh);
        }

        // Handle function selection
        document.getElementById('functionSelect').addEventListener('change', function() {
            const customInput = document.getElementById('customInput');
            customInput.style.display = this.value === 'custom' ? 'block' : 'none';
        });

        // Handle plot button
        document.getElementById('plotButton').addEventListener('click', function() {
            const selectedFunc = document.getElementById('functionSelect').value;

            if (selectedFunc === 'custom') {
                const customExpr = document.getElementById('customFunction').value;
                try {
                    const customFunc = new Function('x', 'y', `return ${customExpr};`);
                    // Test the function
                    customFunc(0, 0);
                    plotFunction(customFunc);
                } catch (e) {
                    alert('Invalid function expression. Please check your syntax.');
                }
            } else {
                plotFunction(functions[selectedFunc]);
            }
        });

        // Initial plot
        plotFunction(functions.paraboloid);

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        // Animation loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        animate();
    </script>
</body>
</html>
