// 5. ANALYZER CLASS (Data Analysis & Processing)
// ==========================================
class Analyzer {
public:
    // Calculate total value
    static double calculateTotalValue(const std::vector<std::unique_ptr<Exhibit>>& exhibits) {
        double total = 0.0;
        for (const auto& e : exhibits) total += e->getValue();
        return total;
    }

    // Filter by year range
    static std::vector<Exhibit*> filterByYear(const std::vector<std::unique_ptr<Exhibit>>& src, int min, int max) {
        std::vector<Exhibit*> result;
        for (const auto& e : src)
            if (e->getYear() >= min && e->getYear() <= max) result.push_back(e.get());
        return result;
    }

    // Filter by artist
    static std::vector<Exhibit*> filterByArtist(const std::vector<std::unique_ptr<Exhibit>>& src, const std::string& artist) {
        std::vector<Exhibit*> result;
        for (const auto& e : src)
            if (e->getArtist() == artist) result.push_back(e.get());
        return result;
    }

    // Sort by value (descending)
    static std::vector<Exhibit*> sortByValue(std::vector<std::unique_ptr<Exhibit>>& src) {
        std::vector<Exhibit*> result;
        for (const auto& e : src) result.push_back(e.get());
        std::sort(result.begin(), result.end(), [](Exhibit* a, Exhibit* b) {
            return a->getValue() > b->getValue();
        });
        return result;
    }
};

