```java
package com.yourname.bounty;

import net.milkbowl.vault.economy.Economy;
import org.bukkit.plugin.RegisteredServiceProvider;
import org.bukkit.plugin.java.JavaPlugin;

import java.util.HashMap;
import java.util.UUID;

public class BountyPlugin extends JavaPlugin {

    private static BountyPlugin instance;
    private static Economy economy = null;
    private HashMap<UUID, Double> bounties;

    @Override
    public void onEnable() {
        instance = this;

        // Save default config
        saveDefaultConfig();

        // Initialize bounties storage
        bounties = new HashMap<>();

        // Setup economy
        if (!setupEconomy()) {
            getLogger().severe("Vault not found! Disabling plugin...");
            getServer().getPluginManager().disablePlugin(this);
            return;
        }

        // Register commands and events
        getCommand("bounty").setExecutor(new BountyCommand());
        getServer().getPluginManager().registerEvents(new BountyListener(), this);

        getLogger().info("BountyPlugin has been enabled!");
    }

    @Override
    public void onDisable() {
        getLogger().info("BountyPlugin has been disabled!");
    }

    private boolean setupEconomy() {
        RegisteredServiceProvider<Economy> economyProvider = getServer().getServicesManager()
                .getRegistration(net.milkbowl.vault.economy.Economy.class);
        if (economyProvider != null) {
            economy = economyProvider.getProvider();
        }
        return (economy != null);
    }

    public static BountyPlugin getInstance() {
        return instance;
    }

    public static Economy getEconomy() {
        return economy;
    }

    public HashMap<UUID, Double> getBounties() {
        return bounties;
    }

    public boolean isWorldEnabled(String worldName) {
        return getConfig().getStringList("enabled-worlds").isEmpty() || 
               getConfig().getStringList("enabled-worlds").contains(worldName);
    }

    public String getMessage(String path) {
        return getConfig().getString("messages." + path, path)
                .replace("&", "§");
    }
}
```

### **4. BountyCommand.java**
```java
package com.yourname.bounty;

import org.bukkit.Bukkit;
import org.bukkit.command.Command;
import org.bukkit.command.CommandExecutor;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;

import java.util.UUID;

public class BountyCommand implements CommandExecutor {

    @Override
    public boolean onCommand(CommandSender sender, Command command, String label, String[] args) {

        // Check if sender is a player for add command
        if (args.length >= 1 && args[0].equalsIgnoreCase("add") && !(sender instanceof Player)) {
            sender.sendMessage("§cOnly players can add bounties!");
            return true;
        }

        if (args.length == 0) {
            sender.sendMessage(BountyPlugin.getInstance().getMessage("usage-check"));
            return true;
        }

        // /bounty add <player> <amount>
        if (args[0].equalsIgnoreCase("add")) {
            if (args.length != 3) {
                sender.sendMessage(BountyPlugin.getInstance().getMessage("usage-add"));
                return true;
            }

            Player player = (Player) sender;

            // Check if world is enabled
            if (!BountyPlugin.getInstance().isWorldEnabled(player.getWorld().getName())) {
                player.sendMessage(BountyPlugin.getInstance().getMessage("world-disabled"));
                return true;
            }

            // Get target player
            Player target = Bukkit.getPlayer(args[1]);
            if (target == null) {
                player.sendMessage("§cPlayer not found!");
                return true;
            }

            // Parse amount
            double amount;
            try {
                amount = Double.parseDouble(args[2]);
            } catch (NumberFormatException e) {
                player.sendMessage(BountyPlugin.getInstance().getMessage("invalid-amount"));
                return true;
            }

            // Validate amount
            if (amount <= 0) {
                player.sendMessage(BountyPlugin.getInstance().getMessage("invalid-amount"));
                return true;
            }

            // Check if player has enough money
            if (!BountyPlugin.getEconomy().has(player, amount)) {
                player.sendMessage(BountyPlugin.getInstance().getMessage("no-money"));
                return true;
            }

            // Withdraw money from player
            BountyPlugin.getEconomy().withdrawPlayer(player, amount);

            // Add to bounty
            UUID targetUUID = target.getUniqueId();
            double currentBounty = BountyPlugin.getInstance().getBounties()
                    .getOrDefault(targetUUID, 0.0);
            BountyPlugin.getInstance().getBounties().put(targetUUID, currentBounty + amount);

            // Send success message
            String message = BountyPlugin.getInstance().getMessage("bounty-added")
                    .replace("%amount%", String.format("%.2f", amount))
                    .replace("%target%", target.getName());
            player.sendMessage(message);

            return true;
        }

        // /bounty <player> - check bounty
        Player target = Bukkit.getPlayer(args[0]);
        if (target == null) {
            sender.sendMessage("§cPlayer not found!");
            return true;
        }

        UUID targetUUID = target.getUniqueId();
        double bounty = BountyPlugin.getInstance().getBounties().getOrDefault(targetUUID, 0.0);

        String message = BountyPlugin.getInstance().getMessage("bounty-check")
                .replace("%target%", target.getName())
                .replace("%amount%", String.format("%.2f", bounty));
        sender.sendMessage(message);

        return true;
    }
}
```

### **5. BountyListener.java**
```java
package com.yourname.bounty;

import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.entity.PlayerDeathEvent;

import java.util.UUID;

public class BountyListener implements Listener {

    @EventHandler
    public void onPlayerDeath(PlayerDeathEvent event) {
        Player victim = event.getEntity();
        Player killer = victim.getKiller();

        // Check if killer is a player
        if (killer == null) {
            return;
        }

        // Check if world is enabled
        if (!BountyPlugin.getInstance().isWorldEnabled(victim.getWorld().getName())) {
            return;
        }

        UUID victimUUID = victim.getUniqueId();
        double bounty = BountyPlugin.getInstance().getBounties().getOrDefault(victimUUID, 0.0);

        // Check if victim has a bounty
        if (bounty <= 0) {
            return;
        }

        // Give money to killer
        BountyPlugin.getEconomy().depositPlayer(killer, bounty);

        // Remove bounty
        BountyPlugin.getInstance().getBounties().remove(victimUUID);

        // Send messages
        String killerMessage = BountyPlugin.getInstance().getMessage("bounty-received")
                .replace("%amount%", String.format("%.2f", bounty))
                .replace("%victim%", victim.getName());
        killer.sendMessage(killerMessage);

        String victimMessage = BountyPlugin.getInstance().getMessage("bounty-paid")
                .replace("%amount%", String.format("%.2f", bounty))
                .replace("%killer%", killer.getName());
        victim.sendMessage(victimMessage);
    }
}
